// Filter rows where Status = 'New Lead' and Message Sent is empty
// Also strips rogue 'json' field that appears when sheet has unnamed columns
const allRows = $input.all();
const cleanLeads = [];

for (const row of allRows) {
  const status = (row.json['Status'] || '').trim();
  const messageSent = (row.json['Message Sent'] || '').trim();

  if (status !== 'New Lead' || messageSent !== '') continue;

  // Strip any rogue 'json' key — unnamed sheet columns get this name internally in N8N
  // Spreading these items later causes: A 'json' property isn't an object
  const cleaned = {};
  for (const key of Object.keys(row.json)) {
    if (key === 'json') continue;
    cleaned[key] = row.json[key];
  }

  cleanLeads.push({ json: cleaned });
}

console.log('New leads to process: ' + cleanLeads.length + ' of ' + allRows.length + ' total rows');
return cleanLeads;

// Generate opener for each lead via Claude API — loops internally, one call per lead
// Mode: Run Once for All Items — uses $input.all() and returns an array
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const lead = items[i].json;

  // Explicitly pick named fields — never spread sheet data
  const bio = String(lead['Notes'] || '').trim();
  const businessName = String(lead['Business Name'] || lead['Instagram Handle'] || 'there').trim();
  const industry = String(lead['Type'] || 'business').trim();
  const location = String(lead['Location'] || 'London').trim();
  const followers = lead['Followers'] || 'unknown';
  const rowNumber = lead['row_number'] || (i + 2); // row_number from sheet, fallback to index
  const handle = String(lead['Instagram Handle'] || '').trim();

  const prompt = 'You are writing a cold Instagram DM opener for a sales outreach campaign.\n\n'
    + 'Lead details:\n'
    + '- Business Name: ' + businessName + '\n'
    + '- Industry: ' + industry + '\n'
    + '- Location: ' + location + '\n'
    + '- Bio: ' + (bio || 'No bio available') + '\n'
    + '- Followers: ' + followers + '\n\n'
    + 'Write ONE short opener DM using this exact formula:\n'
    + '"Hey [Business Name] - saw [something specific from their bio or profile]. [One genuine observation about it]. Would this be the best place to ask you a quick question?"\n\n'
    + 'Rules you must follow exactly:\n'
    + '- Reference something REAL and SPECIFIC from the bio above - not generic\n'
    + '- The observation must be genuine - find one thing worth saying\n'
    + '- Under 3 lines total\n'
    + '- NEVER mention AI, automation, agencies, or technology\n'
    + '- NEVER use generic compliments (no "Love what you\'re doing", "Amazing content", "Great work", etc)\n'
    + '- End with ONE question only\n'
    + '- If the bio contains no useful specific information to reference, output exactly this text: REVIEW NEEDED - add profile detail before sending\n\n'
    + 'Output the DM text only. No explanation. No surrounding quotes.';

  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': 'YOUR_ANTHROPIC_API_KEY',
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: {
      model: 'claude-haiku-4-5',
      max_tokens: 150,
      messages: [{ role: 'user', content: prompt }]
    },
    json: true
  });

  const opener = response.content[0].text.trim();

  results.push({
    json: {
      row_number: rowNumber,
      business_name: businessName,
      instagram_handle: handle,
      industry: industry,
      status: 'Opener Ready',
      opener: opener,
      generated_at: new Date().toISOString().split('T')[0]
    }
  });
}

return results;

// Build email summary — string concatenation only, no template literals
// Template literals with backticks cause N8N parsing issues in Code nodes
const items = $input.all();

var openerLines = '';
var reviewCount = 0;
var readyCount = 0;

for (var i = 0; i < items.length; i++) {
  var handle = items[i].json.instagram_handle || 'unknown';
  var name = items[i].json.business_name || handle;
  var type = items[i].json.industry || '';
  var opener = items[i].json.opener || '';
  var needsReview = opener.indexOf('REVIEW NEEDED') === 0;

  if (needsReview) {
    reviewCount++;
    openerLines += (i + 1) + '. ' + name + ' (' + handle + ') — ' + type + ' [NEEDS REVIEW]\n   ' + opener + '\n\n';
  } else {
    readyCount++;
    openerLines += (i + 1) + '. ' + name + ' (' + handle + ') — ' + type + '\n   ' + opener + '\n\n';
  }
}

var date = new Date().toISOString().split('T')[0];
var total = items.length;

var subject = 'Zizi — ' + total + (total !== 1 ? ' openers' : ' opener') + ' ready (' + date + ')';

var body = 'Workflow 2 — Opener Generation Complete\n\n'
  + 'Date: ' + date + '\n'
  + 'Total processed: ' + total + '\n'
  + 'Ready to send: ' + readyCount + '\n'
  + 'Needs manual review: ' + reviewCount + '\n\n'
  + '---\n\n'
  + openerLines
  + '---\n\n'
  + 'All openers written to Google Sheet under "Message Sent" column.\n'
  + 'Status updated to "Opener Ready".\n\n'
  + 'Zizi: review each opener, personalise if needed, then send from the lead\'s profile.\n'
  + 'Flag anything that looks wrong before sending.';

return [{
  json: {
    subject: subject,
    body: body,
    count: total,
    ready: readyCount,
    review: reviewCount
  }
}];
